/// 中断计数器 — 按中断号统计（最多 32 个中断源）
pub static INTERRUPT_COUNTS: [AtomicU64; 32] = [const { AtomicU64::new(0) }; 32];

/// 记录一次中断
pub fn record_interrupt(irq: usize) {
    if irq < 32 {
        INTERRUPT_COUNTS[irq].fetch_add(1, Ordering::Relaxed);
    }
}

