/// 能力类型
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u8)]
pub enum CapType {
    /// 空能力
    Null = 0,
    /// 内存能力
    Memory = 1,
    /// 线程能力
    Thread = 2,
    /// 端点能力（IPC）
    Endpoint = 3,
    /// 通知能力
    Notification = 4,
    /// 页表能力
    PageTable = 5,
    /// 中断能力
    Interrupt = 6,
    /// 设备能力
    Device = 7,
    /// CNode 能力（能力空间节点）
    CNode = 8,
}

bitflags::bitflags! {
    /// 能力权限标志
    #[derive(Debug, Clone, Copy, PartialEq, Eq)]
    pub struct CapRights: u32 {
        /// 读权限
        const READ = 1 << 0;
        /// 写权限
        const WRITE = 1 << 1;
        /// 执行权限
        const EXECUTE = 1 << 2;
        /// 授权权限（可派生）
        const GRANT = 1 << 3;
        /// 撤销权限
        const REVOKE = 1 << 4;
        /// 全部权限
        const ALL = Self::READ.bits() | Self::WRITE.bits() |
                    Self::EXECUTE.bits() | Self::GRANT.bits() | Self::REVOKE.bits();
    }
}

/// 能力标识符
