pub struct CapId(pub u64);

impl CapId {
    /// 生成新的能力 ID
    pub fn new() -> Self {
        static COUNTER: AtomicU64 = AtomicU64::new(1);
        Self(COUNTER.fetch_add(1, Ordering::Relaxed))
    }

    /// 空能力 ID
    pub const fn null() -> Self {
        Self(0)
    }

    /// 是否为空
    pub fn is_null(&self) -> bool {
        self.0 == 0
    }

    /// 获取内部值
    pub fn value(&self) -> u64 {
        self.0
    }
}

