/// eBPF 指令
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct BpfInsn {
    /// 操作码
    pub code: u8,
    /// 目标寄存器 (低4位) 和源寄存器 (高4位)
    pub regs: u8,
    /// 偏移量
    pub off: i16,
    /// 立即数
    pub imm: i32,
}

impl BpfInsn {
    /// 获取目标寄存器
    pub fn dst_reg(&self) -> u8 {
        self.regs & 0x0F
    }

    /// 获取源寄存器
    pub fn src_reg(&self) -> u8 {
        (self.regs >> 4) & 0x0F
    }

    /// 获取操作码类别
    pub fn class(&self) -> u8 {
        self.code & 0x07
    }
}

