/// Per-inode page cache for MAP_SHARED file-backed mappings. Keyed by
/// `(inode_ptr, page_index)` where `inode_ptr` is `Arc::as_ptr()` cast to
/// usize and `page_index` is the page-aligned file offset divided by
/// PAGE_SIZE. All MAP_SHARED file-backed mappings of the same inode share
/// the same physical frames via this cache, mirroring Linux's page cache
/// semantics. This is essential for IPC via shared memory files (e.g. LTP's
/// `tst_reinit` which re-mmaps an IPC file after exec).
static SHARED_PAGE_CACHE: SpinLock<BTreeMap<(usize, usize), Arc<FrameTracker>>> =
    SpinLock::new(BTreeMap::new());

/// Look up or allocate a page in the shared page cache for a MAP_SHARED
/// file-backed mapping.
pub fn shared_cache_get_or_insert(
    inode_ptr: usize,
    page_index: usize,
) -> Option<Arc<FrameTracker>> {
    let mut cache = SHARED_PAGE_CACHE.lock();
    if let Some(frame) = cache.get(&(inode_ptr, page_index)) {
        return Some(frame.clone());
    }
    let frame = frame_alloc()?;
    let arc = Arc::new(frame);
    cache.insert((inode_ptr, page_index), arc.clone());
    Some(arc)
}

/// Get an existing page from the shared cache (no allocation).
pub fn shared_cache_get(inode_ptr: usize, page_index: usize) -> Option<Arc<FrameTracker>> {
    let cache = SHARED_PAGE_CACHE.lock();
    cache.get(&(inode_ptr, page_index)).cloned()
}

/// Insert a frame into the shared page cache.
pub fn shared_cache_insert(inode_ptr: usize, page_index: usize, frame: Arc<FrameTracker>) {
    let mut cache = SHARED_PAGE_CACHE.lock();
    cache.insert((inode_ptr, page_index), frame);
}

/// Evict the shared page-cache entries of inode `inode_ptr` for file page
/// indices `[start_idx, end_idx)`. Used by `msync(MS_INVALIDATE)` so the next
/// fault on the range re-reads the page from the backing file (a genuine major
/// fault) rather than silently reusing the still-cached frame as a near-zero
/// minor fault. Dropping the cache's `Arc` frees the physical page once no live
/// mapping still references it (a live mapping keeps its own `Arc` in
/// `Vma::frames`, so its PTE stays valid until it re-faults).
pub fn shared_cache_evict_range(inode_ptr: usize, start_idx: usize, end_idx: usize) {
    if start_idx >= end_idx {
        return;
    }
    let mut cache = SHARED_PAGE_CACHE.lock();
    let victims: Vec<(usize, usize)> = cache
        .range((inode_ptr, start_idx)..(inode_ptr, end_idx))
        .map(|(k, _)| *k)
        .collect();
    for k in victims {
        cache.remove(&k);
    }
}

