    pub struct PTEFlags: u8 {
        /// Valid - 页表项有效
        const V = 1 << 0;
        /// Read - 可读
        const R = 1 << 1;
        /// Write - 可写
        const W = 1 << 2;
        /// Execute - 可执行
        const X = 1 << 3;
        /// User - 用户态可访问
        const U = 1 << 4;
        /// Global - 全局映射
        const G = 1 << 5;
        /// Accessed - 已访问
        const A = 1 << 6;
        /// Dirty - 已修改
        const D = 1 << 7;
    }
}

