fn write_u32(val: u32) {
    let mut buf = [0u8; 10];
    let len = write_u32_to_buf(val, &mut buf);
    sys_write(1, &buf[..len]);
}

fn write_i32(val: i32) {
    if val < 0 {
        write_str(b"-");
        write_u32((-val) as u32);
    } else {
        write_u32(val as u32);
